mapper.select:
Select Top 500 Row_Number()OVER(ORDER BY AssignedDate DESC ) as RNUM, TMI.Seq, TMI.MemberID, TM.Name + '('+ ISNULL(TM.NameEN,'') + ')' As Name, TMI.ItemID, TMI.RoleType, TD.Name As RoleTypeTxt, TM.TeamID, Assigned, CASE Assigned WHEN '1' THEN 'Y' Else 'N' END AS Assignment , ISNULL(CONVERT(char(10),TMI.AssignedDate, 111),'') as AssignedDate, ISNULL(XBOLTADM.fn_GetMyAbsPathForOrg(TM.TeamID , #{languageID}), '') + '/' + TTT.Name AS Path, XBOLTADM.fn_GetMyAbsPath(TMI.ItemID , CONVERT(INT, #{languageID})) AS itemPath, TMI.AssignmentType, TD2.Name As AssignmentTypeName, TMI.OrderNum, Case When ISNULL(TM.Photo,'blank_photo.png') = 'blank_photo.png' Then #{blankPhotoUrlPath} Else #{photoUrlPath} + ISNULL(TM.Photo,'blank_photo.png') END AS Photo, TMI.AccessRight, CASE TMI.AccessRight WHEN 'R' THEN 'Referred' Else 'Manage' END AS AccessRightName From XBOLTADM.TB_MY_ITEM TMI Left Outer Join XBOLTADM.TB_MEMBER TM ON TM.MemberID = TMI.MemberID Left Outer Join XBOLTADM.TB_TEAM_TXT TTT On TM.TeamID = TTT.TeamID AND TTT.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TD On TD.TypeCode = TMI.RoleType And TD.Category = TMI.AssignmentType And TD.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TD2 ON TD2.TypeCode = TMI.AssignmentType And TD2.Category = 'ROLECAT' And TD2.LanguageID = #{languageID}
And TMI.ItemID = #{itemID}
And TMI.Assigned = #{assigned}
AND TMI.AssignmentType = #{assignmentType}
AND TM.MemberID = #{memberId}
Order By TMI.AssignmentType, TMI.RoleType, TMI.OrderNum, TMI.AssignedDate DESC

Select Top 500 Row_Number()OVER(ORDER BY TMI.AssignmentType, TMI.RoleType, TMI.OrderNum, TMI.AssignedDate ) as RNUM, TMI.Seq, TMI.MemberID, TM.Name + '('+ ISNULL(TM.NameEN,'') + ')' As Name, TMI.ItemID, TMI.RoleType, CLSTD.Name AS className, TD.Name As RoleTypeTxt, TM.TeamID, TMI.Assigned, CASE TMI.Assigned WHEN '1' THEN 'Y' Else 'N' END AS Assignment , ISNULL(CONVERT(char(10),TMI.AssignedDate, 111),'') as AssignedDate, XBOLTADM.fn_GetMyAbsPathForList(TMI.ItemID , CONVERT(INT, 1042))+'/'+TIA.PlainText AS itemPath, TMI.AssignmentType, TD2.Name As AssignmentTypeName, TMI.OrderNum, TMI.AccessRight, CASE TMI.AccessRight WHEN 'R' THEN 'Referred' Else 'Manage' END AS AccessRightName From XBOLTADM.TB_MY_ITEM TMI Left Outer Join XBOLTADM.TB_MEMBER TM ON TM.MemberID = TMI.MemberID Left Outer Join XBOLTADM.TB_TEAM_TXT TTT On TM.TeamID = TTT.TeamID AND TTT.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TD On TD.TypeCode = TMI.RoleType And TD.Category = TMI.AssignmentType And TD.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TD2 ON TD2.TypeCode = TMI.AssignmentType And TD2.Category = 'ROLECAT' And TD2.LanguageID = #{languageID} Inner Join XBOLTADM.TB_ITEM TI ON TI.ItemID = TMI.ItemID Inner Join XBOLTADM.TB_DICTIONARY CLSTD ON CLSTD.TypeCode = TI.ClassCode AND CLSTD.LanguageID = #{languageID} Inner JOIN XBOLTADM.TB_ITEM_ATTR TIA ON TIA.ItemID = TI.ItemID AND TIA.LanguageID = #{languageID} AND TIA.AttrTypeCode = 'AT00001'
where TM.MemberID = #{memberId} AND TMI.AssignmentType != 'SUBSCR'
AND TMI.AssignmentType = #{assignmentType}
AND TMI.Assigned = #{assigned}
Order By TMI.AssignmentType, TMI.RoleType, TMI.OrderNum, TMI.AssignedDate DESC

mapper.delete:
  	Delete FROM XBOLTADM.TB_MY_ITEM
	
		
			Seq = #{seq} 
		
		
			MemberID = #{memberID} 
		
		
			AND ItemID = #{itemID}
		
		
			AND AssignmentType = #{assignmentType}

mapper.select:
Select TeamID From XBOLTADM.TB_TEAM_ROLE
Where TeamID = #{teamID}
And ItemID = #{itemID}

	And Assigned = #{assigned}

Select Row_Number()OVER(ORDER BY TD.SortNum, XBOLTADM.fn_GetMyAbsPathForOrg(TMT.TeamID , #{languageID}), TMT.Name ASC ) AS RNUM , 0 AS CHK , TeamRoleID , ISNULL(TT.TeamCode,'') AS TeamCode , ISNULL(TMT.Name,'') AS TeamNM , XBOLTADM.fn_GetMyAbsPathForOrg(TMT.TeamID , #{languageID}) AS TeamPath , ISNULL(TD.Name,'') AS TeamRoleNM , ISNULL(CONVERT(char(10),TTR.AssignedDate, 111),'') AS AssignedDate , ISNULL(TTR.RoleManagerID,TT.RoleManagerID) As RoleManagerID , ISNULL(TM1.Name,ISNULL(TM.NAME,'N/A')) As RoleManagerNM , TTR.ItemID , TTR.TeamRoletype , TD.SortNum , TTR.TeamID , TT.ManagerID AS TeamManagerID , TT.RoleManagerID AS curRoleManagerID From XBOLTADM.TB_TEAM_ROLE TTR Left Outer Join XBOLTADM.TB_TEAM TT ON TT.TeamID = TTR.TeamID Left Outer Join XBOLTADM.TB_TEAM_TXT TMT ON TMT.TeamID = TTR.TeamID And TMT.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TD On TD.TypeCode = TTR.TeamRoleType And TD.Category = 'TEAMROLETP' And TD.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_MEMBER TM ON TM.MemberID = TTR.RoleManagerID Left Outer Join XBOLTADM.TB_MEMBER TM1 ON TM1.MemberID = TT.RoleManagerID Where TTR.ItemID = #{itemID}
And ItemID = #{itemID}
And Assigned = #{assigned}
And RoleType = #{roleType},
AND AssignmentType = #{assignmentType}
ORDER BY SortNum, TeamPath, TeamNM ASC

mapper.insert:

	Insert Into XBOLTADM.TB_TEAM_ROLE 
		(
		 TeamID
		  ,TeamCode
		, ItemID, TeamRoleCat
		, TeamRoleType, Assigned, AssignedDate
		, Creator, LastUpdated
		
		)
	Values( 
		 #{teamID}
		  ,#{teamCode}
		, #{itemID}, #{teamRoleCat}
		, #{teamRoleType}, #{assigned}
		, GETDATE()
		, #{creator}, GETDATE() )

mapper.update:

	Update XBOLTADM.TB_TEAM_ROLE Set 
		LastUpdated = GETDATE()
		 ,TeamRoleType = #{teamRoleType} 
		 ,RoleManagerID = #{roleManagerID} 
		 ,Assigned = #{assigned} 
	Where 1=1
	
	 And TeamRoleID = #{teamRoleID}
	 
	 
	 And TeamRoleID IN(${teamRoleIDs})

mapper.select:
Select Top 1000 Row_Number() OVER(ORDER BY TI.ItemTypeCode ASC, TI.Identifier ASC, TIA.PlainText ASC ) AS RNUM , 0 AS CHK , ISNULL(TIT.Icon, 'img_job.png') ItemTypeImg , TI.Identifier , ISNULL(TIA.PlainText,'') As ItemNM , TDC.Name AS ClassName , TI.ClassCode , TI.ItemTypeCode , ISNULL(PJTXT.Name,'') AS PjtName , ISNULL(XBOLTADM.fn_GetMyAbsPathForList( TI.ItemID, #{languageID}),'') AS Path , Convert(nvarchar(20),TI.LastUpdated, 111) AS LastUpdated , ISNULL(TDS.Name,'') AS StatusNM , TI.Status , TI.ItemID , TI.Blocked , ISNULL(TD.Name,'') AS TeamRoleNM , TTR.TeamRoleType , TTR.RoleManagerID , ISNULL(TM.Name, ISNULL(TM1.Name,'N/A'))As RoleManagerNM , TTR.TeamRoleID From XBOLTADM.TB_TEAM_ROLE TTR Left Outer Join XBOLTADM.TB_ITEM TI ON TI.ItemID = TTR.ItemID Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA ON TIA.ItemID = TI.ItemID And TIA.AttrTypeCode = 'AT00001' And TIA.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TDC ON TDC.TypeCode = TI.ClassCode And TDC.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_PROJECT CSR ON CSR.ProjectID = TI.ProjectID LEFT OUTER JOIN XBOLTADM.TB_PROJECT_TXT PJTXT ON PJTXT.ProjectID = CSR.RefPjtID and PJTXT.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM ON TTR.RoleManagerID = TM.MemberID LEFT OUTER JOIN XBOLTADM.TB_ITEM_CLASS TCLS ON TCLS.ItemClassCode = TI.ClassCode LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TDS ON TI.Status = TDS.TypeCode AND TDS.Category = 'ITMSTS' AND TDS.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM_TYPE TIT ON TI.ItemTypeCode = TIT.ItemTypeCode LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TD On TD.TypeCode = TTR.TeamRoleType And TD.Category = 'TEAMROLETP' And TD.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_TEAM TT ON TT.TeamID = TTR.TeamID LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM1 ON TM1.MemberID = TT.RoleManagerID Where TI.Deleted != 1 AND TI.CategoryCode = 'OJ' And TTR.TeamID = #{teamID}
And TTR.RoleManagerID = #{roleManagerID}
And TTR.TeamRoleType = #{teamRoleType}
And TI.ItemTypeCode = #{itemTypeCode}
And TI.ClassCode = #{classCode}
And TI.Status = #{status}
AND TIA.PlainText like N'%'+#{searchValue}+'%'
AND TI.Identifier Like N'%'+#{searchValue}+'%'
Order By ItemTypeCode, Identifier , ItemNM

Select
	Row_Number()OVER(ORDER BY TTR.TeamRoleID ASC ) AS RNUM
	, TTR.TeamRoleID
	, ISNULL(TT.TeamCode,'') AS TeamCode
	, ISNULL(TMT.Name,'') AS TeamNM
	, XBOLTADM.fn_GetMyAbsPathForOrg(TTR.TeamID , #{languageID}) AS TeamPath
	, ISNULL(TD.Name,'') AS TeamRoleNM
	, TI.Identifier AS ID
	, TIA.PlainText AS ItemName
	, TDC.Name AS ClassName
	, ISNULL(CONVERT(char(10),TTR.LastUpdated, 111),'') AS LastUpdated
	, Case When TTR.Assigned = '1' Then 'Active' 
	   When TTR.Assigned = '0' Then 'Removed' End AS StatusNM
From XBOLTADM.TB_TEAM_ROLE TTR
Left Outer Join XBOLTADM.TB_TEAM TT ON TT.TeamID = TTR.TeamID
Left Outer Join XBOLTADM.TB_TEAM_TXT TMT ON TMT.TeamID = TTR.TeamID And TMT.LanguageID = #{languageID}
Left Outer Join XBOLTADM.TB_TEAM_TXT TMPT ON TMPT.TeamID = TT.ParentID And TMPT.LanguageID = #{languageID}
Left Outer Join XBOLTADM.TB_DICTIONARY TD On TD.TypeCode = TTR.TeamRoleType And TD.Category = 'TEAMROLETP' And TD.LanguageID =#{languageID}
Left OUter Join XBOLTADM.TB_ITEM TI ON TI.ItemID = TTR.ItemID 
Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA ON TIA.ItemID = TTR.ItemID And TIA.AttrTypeCode = 'AT00001' And TIA.LanguageID = #{languageID}
Left Outer Join XBOLTADM.TB_DICTIONARY TDC ON TDC.TypeCode = TI.ClassCode And TDC.Category = 'CLS' And TDC.LanguageID = #{languageID}	
Where 1=1	

	And TT.CompanyID = #{companyID}


	And TTR.TeamID = #{teamID}


	And TTR.Assigned = #{assigned}


	And TTR.TeamRoleType = #{teamRoleType}

Select Count(*) From XBOLTADM.TB_MY_ITEM 
Where ItemID = #{itemID}
And MemberID = #{memberID}
And AssignMentType = #{assignmentType}
And RoleType = #{roleType}

select Row_Number()OVER(ORDER BY TD.SortNum, XBOLTADM.fn_GetMyAbsPathForOrg(TMT.TeamID , #{languageID}), TMT.Name ASC ) AS RNUM , 0 AS CHK , TeamRoleID , ISNULL(TT.TeamCode,'') AS TeamCode , ISNULL(TMT.Name,'') AS TeamNM , XBOLTADM.fn_GetMyAbsPathForOrg(TMT.TeamID , #{languageID}) AS TeamPath , ISNULL(TD.Name,'') AS TeamRoleNM , ISNULL(CONVERT(char(10),TTR.AssignedDate, 111),'') AS AssignedDate , ISNULL(TTR.RoleManagerID,TT.RoleManagerID) As RoleManagerID , ISNULL(TM.NAME,ISNULL(TM1.Name,'N/A')) As RoleManagerNM , TTR.ItemID , TTR.TeamRoletype , TD.SortNum , TTR.TeamID , TT.ManagerID AS TeamManagerID , TT.RoleManagerID AS curRoleManagerID FROM XBOLTADM.TB_ITEM A INNER JOIN XBOLTADM.TB_ITEM B ON A.ItemID = B.ToItemID AND B.CategoryCode = 'ST1' AND B.Deleted != 1
INNER Join XBOLTADM.TB_ITEM TIC ON A.ItemID = TIC.ToItemID AND TIC.CategoryCode = 'CN' Left Outer Join XBOLTADM.TB_TEAM_ROLE TTR ON TTR.ItemID = TIC.FromItemID AND TIC.ClassCode = 'CNL0201A'
Left Outer Join XBOLTADM.TB_TEAM TT ON TT.TeamID = TTR.TeamID Left Outer Join XBOLTADM.TB_TEAM_TXT TMT ON TMT.TeamID = TTR.TeamID And TMT.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TD On TD.TypeCode = TTR.TeamRoleType And TD.Category = 'TEAMROLETP' And TD.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_MEMBER TM ON TM.MemberID = TTR.RoleManagerID Left Outer Join XBOLTADM.TB_MEMBER TM1 ON TM1.MemberID = TT.RoleManagerID where B.FromItemID = #{s_itemID}
